func testUserProfileToOneSetOpFamilyStatusUsingChildrenStatus(t *testing.T) {
	var err error

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()

	var a UserProfile
	var b, c FamilyStatus

	seed := randomize.NewSeed()
	if err = randomize.Struct(seed, &a, userProfileDBTypes, false, strmangle.SetComplement(userProfilePrimaryKeyColumns, userProfileColumnsWithoutDefault)...); err != nil {
		t.Fatal(err)
	}
	if err = randomize.Struct(seed, &b, familyStatusDBTypes, false, strmangle.SetComplement(familyStatusPrimaryKeyColumns, familyStatusColumnsWithoutDefault)...); err != nil {
		t.Fatal(err)
	}
	if err = randomize.Struct(seed, &c, familyStatusDBTypes, false, strmangle.SetComplement(familyStatusPrimaryKeyColumns, familyStatusColumnsWithoutDefault)...); err != nil {
		t.Fatal(err)
	}

	if err := a.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Fatal(err)
	}
	if err = b.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Fatal(err)
	}

	for i, x := range []*FamilyStatus{&b, &c} {
		err = a.SetChildrenStatus(ctx, tx, i != 0, x)
		if err != nil {
			t.Fatal(err)
		}

		if a.R.ChildrenStatus != x {
			t.Error("relationship struct not set to correct value")
		}

		if x.R.ChildrenStatusUserProfiles[0] != &a {
			t.Error("failed to append to foreign relationship struct")
		}
		if !queries.Equal(a.ChildrenStatusID, x.ID) {
			t.Error("foreign key was wrong value", a.ChildrenStatusID)
		}

		zero := reflect.Zero(reflect.TypeOf(a.ChildrenStatusID))
		reflect.Indirect(reflect.ValueOf(&a.ChildrenStatusID)).Set(zero)

		if err = a.Reload(ctx, tx); err != nil {
			t.Fatal("failed to reload", err)
		}

		if !queries.Equal(a.ChildrenStatusID, x.ID) {
			t.Error("foreign key was wrong value", a.ChildrenStatusID, x.ID)
		}
	}
}

